import{_ as a,o as t,c as p,j as r,a as b,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"熊熊抱","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/熊熊抱.md","filePath":"4.资源分区/7.物品与装备/6.套装/熊熊抱.md"}'),s={name:"4.资源分区/7.物品与装备/6.套装/熊熊抱.md"};function o(d,e,l,_,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"熊熊抱",tabindex:"-1"},[b("熊熊抱 "),r("a",{class:"header-anchor",href:"#熊熊抱","aria-label":'Permalink to "熊熊抱"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调015")])])],-1),n('<h1 id="熊熊抱-1" tabindex="-1">熊熊抱 <a class="header-anchor" href="#熊熊抱-1" aria-label="Permalink to &quot;熊熊抱&quot;">​</a></h1><p>熊熊抱</p><p>熊熊抱<br> C+1000<br> 不要被它毛茸茸的可爱外表所迷惑，它的力量远超我们的想象。</p><p>武器类别：拳套<br> 使用专业：拳<br> 武器伤害：0L+5附加成功</p><p>特殊效果：<br> 以此武器进行攻击命中后，会在目标身上留下一层【依恋】。同一时间，【依恋】只会存在于一个单位身上。<br> 当一个单位身上的【依恋】层数达到两层以后，人物对其进行的下一次攻击或者擒抱检定可获得【依恋】层数+1点附加成功。这之后移除依恋层数。<br> 当以此武器进行的擒抱检定若成功压制对方，则在压制状态持续期间，对方还会陷入C级别创伤来源的【窒息】状态。</p><p>熊熊抱<br> C+1000<br> 或许它的身体曾经是毛茸茸的，但如今却因为破烂而显得寒酸。<br> 修复它的请求被果断回绝。<br> 那些在它印象中对拥抱的温暖记忆，伴随着对它的抛弃一并消逝了。<br> 如果这只熊喜欢你身上被遗忘的童真，那些棉花就会从裂缝中伸出。</p><p>盔甲类型：重甲<br> 盔甲防御：15/15<br> 盔甲减值：4<br> 特性：【适应】、精神伤害易伤2<br> 【紧密拥抱】：穿戴这件盔甲以后，你内心涌动出一股渴望，渴望与他人拥抱，渴望获得爱。<br> 这意味着你在进行擒抱检定时，会无视体积差带来的优势与劣势。<br> 你进行擒抱对抗时，获得决心附加点增强加值。</p><p>头饰<br> C+1000<br> 占据饰品位</p><p>特性：<br> 穿戴者无视沮丧点数带来的减值。但一旦穿戴者因沮丧点数进入了严重状态，它将会失去人生存在的意义，这将修改沮丧点数带来的严重状态效果，转而令人物处于震慑状态。<br> 穿戴者的意志池上限提高5点。</p><p>套装效果<br> 穿戴所有组件后，人物获得以下效果：<br> 施加的依恋层数增加人物的决心附加成功层。<br> 获得基于盔甲防御的【坚韧】效果。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',12)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
